import React from "react";
import { useLocation, useNavigate } from "react-router-dom";
import Topnav from "../components/Topnav";
import Footer from "../components/Footer";

function Result() {
  const navigate = useNavigate();
  const location = useLocation();

  const {
    gem_prediction = "Unknown",
    gem_confidence = 0,
    shape_prediction = "",
    shape_confidence = 0,
    image,
    show_shape = false,
  } = location.state || {};

  const gemConf = (gem_confidence * 100).toFixed(1);
  const shapeConf = (shape_confidence * 100).toFixed(1);

  return (
    <>
      <Topnav />

      <main className="min-h-screen bg-[#0a1425] text-white flex flex-col items-center justify-center py-12 px-6">
        <div className="w-full max-w-4xl">
          {/* Gem Name - Large & Bold */}
          <h1 className="text-5xl md:text-7xl font-bold text-center mb-10 tracking-tight text-[#60a5fa]">
            {gem_prediction}
          </h1>

          {/* Image Container */}
          {image && (
            <div className="flex justify-center mb-12">
              <div className="relative w-80 md:w-96 aspect-square rounded-2xl overflow-hidden shadow-2xl shadow-black/70 border-4 border-[#1e40af]/30">
                <img
                  src={URL.createObjectURL(image)}
                  alt={gem_prediction}
                  className="w-full h-full object-cover"
                />
              </div>
            </div>
          )}

          {/* Result Info - Centered Blocks */}
          <div className="space-y-10 text-center max-w-2xl mx-auto">
            {/* Gem Identification */}
            <div>
              <div className="text-lg md:text-xl text-slate-400 mb-2">
                Gem Identification
              </div>
              <div className="text-3xl md:text-4xl font-semibold mb-3">
                {gem_prediction}
              </div>
              <div className="inline-block px-6 py-3 bg-[#1e40af]/60 rounded-full text-[#60a5fa] font-medium text-lg shadow-md">
                Confidence: {gemConf}%
              </div>
            </div>

            {/* Shape / Cut (only if enabled) */}
            {show_shape && shape_prediction && (
              <div>
                <div className="text-lg md:text-xl text-slate-400 mb-2">
                  Shape / Cut
                </div>
                <div className="text-3xl md:text-4xl font-semibold mb-3 capitalize">
                  {shape_prediction}
                </div>
                <div className="inline-block px-6 py-3 bg-[#1e40af]/60 rounded-full text-[#60a5fa] font-medium text-lg shadow-md">
                  Confidence: {shapeConf}%
                </div>
              </div>
            )}
          </div>

          {/* Re-Analyze Button */}
          <div className="mt-16 flex justify-center">
            <button
              onClick={() => navigate("/imageuploader")}
              className="px-10 py-5 md:px-14 md:py-6 bg-[#3b82f6] hover:bg-[#2563eb] text-white text-xl md:text-2xl font-semibold rounded-full transition-all duration-300 shadow-xl shadow-[#3b82f6]/40 hover:shadow-2xl hover:shadow-[#3b82f6]/60 hover:scale-105 focus:outline-none focus:ring-4 focus:ring-[#60a5fa]/50"
            >
              Re-Analyze Another Gem
            </button>
          </div>
        </div>
      </main>

      <Footer />
    </>
  );
}

export default Result;
